import { Component, OnInit } from '@angular/core';
import { Employee } from '../model/employee';
import { HttpService } from '../http.service';

@Component({
  selector: 'app-addemp',
  templateUrl: './addemp.component.html',
  styleUrls: ['./addemp.component.css']
})
export class AddempComponent implements OnInit{

    addData:Employee=<Employee>{};
    allCountry:any[]=[];

    constructor(private service:HttpService){} 

    ngOnInit(): void {
        this.getAllCountryFromBackend();     
    }

     getAllCountryFromBackend(){
         this.service.getAllCountry()
         .subscribe((response:any)=>{
          this.allCountry=response;
         })
     }

    onSubmit(){
      this.addData.createdDate=Date.now();
      this.addData.updatedDate=Date.now();
      this.addData.createdBy="admin",
      this.addData.updateBy="admin";

      this.service.postEmpData(this.addData)
      .subscribe((resp))
    }

}
<p>addemp works!</p>

<br />

<div class="container">
    <div class="row">
        <div class="col">
            <label for="">Name::</label>
            <input [(ngModel)]="addData.name" type="text" class="form-control" placeholder="Enter the Name"><br>

            <label for="">Status::</label>
            <input [(ngModel)]="addData.status" type="text" class="form-control" placeholder="Enter the Status"><br>

            <label for="">Department::</label>
            <input [(ngModel)]="addData.department" type="text" class="form-control" placeholder="Enter the Department"><br>

            <label for="">Mobileno::</label>
            <input [(ngModel)]="addData.mobileno" type="tel" class="form-control" placeholder="Enter the Mobileno"><br>

            <label for="">Email Id::</label>
            <input [(ngModel)]="addData.emailid" type="email" class="form-control" placeholder="Enter the Email Id"><br>

            <label for="">salary::</label>
            <input [(ngModel)]="addData.salary" type="number" class="form-control" placeholder="Enter the salary"><br>

            <label for="">Country::</label>
            <select [(ngModel)]="addData.country" class="form-control" name="" id="">
               <option [ngValue]="item" *ngFor="let item of allCountry" > {{item.cname}} </option>
            </select>
            <br>
            <button (click)="onSubmit()" class="btn btn-success">Submit</button>
            <br>

        </div>
    </div>

</div>
<br/>
